INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-02269', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列關於驗配軟式老花多焦點（soft multifocal）隱形眼鏡的臨床技巧，何者錯誤？', '["若遠用與近用視力皆不佳時，先處理遠用視力再來調整近用視力", "試戴片戴上後先等待10～20分鐘讓鏡片穩定，再進行檢測與評估", "單眼戴鏡驗光（over-refraction）時也讓雙眼都張開才能更清楚雙眼並用時的視力狀態", "兩個眼睛的近用加入度（ADD）必須要一致，以提供平衡的近用視力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02270', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列關於單眼視覺法（monovision）的驗配與檢測，何者正確？', '["若單眼視覺法隱形眼鏡無法完全滿足患者的視力需求，則就算多配一副框架眼鏡搭配運用也是沒幫助的", "此種驗配法通常會在主要眼配戴近用視力鏡片，非主要眼（non-dominant eye）配戴遠用視力鏡片", "散光度數大於1.50 D以上才考慮矯正其散光，低於1.50 D的散光對視力的影響與驗配成功率並無影響", "患者在單眼視覺法與框架眼鏡的立體視覺（stereopsis）與對比敏感度（contrast sensitivity）若非常相似， 是一個成功驗配的徵兆"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02271', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者是聚甲基丙烯酸甲酯（polymethyl methacrylate, PMMA）逐漸不為隱形眼鏡材質的主要原因？', '["易有沉積物", "透氧率低", "透光度差", "濕潤度低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02272', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者是隱形眼鏡材料中使用矽氧烷丙烯酸酯（silicone/acrylate）的缺點？', '["鏡片尺寸穩定性", "鏡片柔曲有限", "會吸引眼淚中的蛋白質", "隱形眼鏡的抗刮性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02273', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有一含水量38%隱形眼鏡材質，並帶負電，依美國FDA軟式隱形眼鏡分類屬於第幾類材質？', '["一", "二", "三", "四"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02274', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者不是隱形眼鏡引起之角膜輪部充血（limbal redness）的常見原因？', '["角膜缺氧反應", "角膜翹曲變形（warpage）", "鏡片邊緣設計不良", "角結膜潛在疾病"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02275', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式水膠隱形眼鏡含水量之敘述，下列何者錯誤？', '["軟式水膠隱形眼鏡含水量會因溫度改變而有所改變", "離子性軟式水膠隱形眼鏡含水量會因pH值的變化而有所改變", "軟式水膠隱形眼鏡含水量越高，其會降低鏡片的耐用性", "軟式水膠隱形眼鏡含水量越高，折射率越高"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02276', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者是氟與矽的氟矽丙烯酸酯（fluoro-silicone/acrylate）單體做為硬式透氣隱形眼鏡的優點？', '["矽可以增加材料的親水性，降低濕潤角（wetting angle），配戴舒服不易模糊", "矽可以強化材料的硬度（rigidity），使得反覆搓洗及配戴下也不容易產生鏡片變形", "氟與矽可增加材料的透氧率（oxygen permeability, Dk），角膜較不容易缺氧", "矽可以讓材料表面較安定，不容易讓蛋白質附著及沉澱（deposit）在鏡片表面"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02277', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '聚甲基丙烯酸羥乙酯（p-HEMA）材質的隱形眼鏡，主要是根據美國FDA對軟式隱形眼鏡材質的何種特 性做分類？', '["透氧率及離子特性（ionic character）", "濕潤度和傳氧率（oxygen transmissibility, Dk/L）", "含水量（water content）及傳氧率", "含水量及離子特性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02278', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有一片軟式水膠隱形眼鏡，在尚未水化（hydration）前鏡片重量為0.05克，水化後鏡片重量為0.08克， 該鏡片的含水量為多少？', '["30%", "37.5%", "60%", "62.5%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
